section.sourcecode:
frame = { "t" : frame-type, ? "x" : [+ codec-id], ? "pub": any, ? "to": [+ recipient], ? "d" : bstr / any, "prev": content-id, "id" : content-id, ? "sig": bstr, }
frame-type = "terms" / "quads" / "reifies" / "annot" / "blob" / "suppress" / "snapshot" / "meta" / "index" / "opaque"
recipient = { "kid": tstr, ? "alg": tstr, * tstr => any }

reifies-payload = { * term-id => [term-id, term-id, term-id] }
quads-payload = [+ [term-id, term-id, term-id, ? term-id]]
annot-payload = [+ [term-id, term-id, term-id]]

gts-item = header-item / frame header-item = header / self-described-header self-described-header = #6.55799(header)
term-id = uint frame-index = uint codec-id = uint digest = bstr .size 32 content-id = digest blake3-uri = tstr digest-ref = digest / blake3-uri profile-name = tstr layout-state = "streamable" / tstr extension-key = tstr
header = { "gts": "GTS1", "v": 1, "prof": profile-name, "cat": { * codec-id => codec }, ? "layout": layout-state, ? "dct": { * tstr => bstr }, ? "meta": any, "id": content-id, * extension-key => any, }
codec = { "name": tstr, "cls": "encode" / "compress" / "encrypt", ? "dct": tstr, ? "p": any, * extension-key => any, }
frame = { "t": frame-type, ? "x": [+ codec-id], ? "pub": any, ? "to": [+ recipient], ? "d": frame-payload / bstr, "prev": content-id, "id": content-id, ? "sig": cose-sign1, * extension-key => any, }
frame-type = "terms" / "quads" / "reifies" / "annot" / "blob" / "suppress" / "snapshot" / "meta" / "index" / "opaque"
recipient = { "kid": tstr, ? "alg": tstr, * extension-key => any, }
cose-sign1 = bstr
frame-payload = terms-payload / quads-payload / reifies-payload / annot-payload / blob-payload / suppress-payload / snapshot-payload / meta-payload / index-payload / opaque-node
terms-payload = [+ term] term = { "k": 0 / 1 / 2 / 3, ? "v": tstr, ? "dt": term-id, ? "l": tstr, ? "dir": "ltr" / "rtl", ? "rf": term-id, * extension-key => any, }
triple-row = [term-id, term-id, term-id] quad-row = [term-id, term-id, term-id] / [term-id, term-id, term-id, term-id]
quads-payload = [+ quad-row] reifies-payload = { * term-id => triple-row } annot-payload = [+ triple-row]
blob-payload = bstr blob-pub = { ? "mt": tstr, ? "rep": tstr, ? "digest": digest-ref, * extension-key => any, }
suppress-payload = { "targets": [+ suppress-target], ? "reason": tstr, ? "by": term-id, * extension-key => any, }
suppress-target = suppress-frame / suppress-blob / suppress-term / suppress-quad / suppress-reifier suppress-frame = { "kind": "frame", "id": digest-ref, * extension-key => any } suppress-blob = { "kind": "blob", "digest": digest-ref, * extension-key => any } suppress-term = { "kind": "term", "id": term-id, * extension-key => any } suppress-quad = { "kind": "quad", "q": quad-row, * extension-key => any } suppress-reifier = { "kind": "reifier", "id": term-id, * extension-key => any }
snapshot-payload = { "terms": terms-payload, ? "quads": quads-payload, ? "reifies": reifies-payload, ? "annot": annot-payload, ? "blobs": { * digest-ref => bstr }, ? "meta": any, * extension-key => any, }
meta-payload = any
index-payload = { "count": uint, "head": content-id, ? "off": [+ uint], ? "ti": { * frame-type => [+ frame-index] }, ? "dict": [+ frame-index], ? "mmr": content-id, * extension-key => any, }
opaque-node = { "id": content-id, "type": frame-type, ? "pub": any, ? "to": [+ recipient], ? "sigstat": sig-status, "reason": opaque-reason, * extension-key => any, }
sig-status = "none" / "valid" / "invalid" / "unverified" opaque-reason = "unknown-codec" / "missing-key" / "damaged" / "unknown-frame-type"
diagnostic = { "code": diagnostic-code, "detail": tstr, ? "frame_index": frame-index, * extension-key => any, }
diagnostic-code = "EmptyFile" / "TornAppendError" / "DamagedFrame" / "BrokenChain" / "TruncatedLog" / "UnknownCodec" / "MissingKey" / "KeyWrapFailed" / "ConflictingReifier" / "IllTypedLiteral" / "RecursionLimit" / "StreamableLayoutError" / "PositionConstraint" / "ForwardReference" / "SegmentBoundary" / "IndexMmrError" / "UnknownFrameType" / tstr
profile-status = "core-required" / "optional-standard" / "experimental" / "domain-specific" profile-registration = { "name": profile-name, "status": profile-status, ? "owner": tstr, ? "spec": tstr, ? "namespace": [+ tstr], ? "requires": any, ? "validation": any, ? "security": any, * extension-key => any, }
